// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;
import "./RoleManager.sol";
import "./AuditLog.sol";

contract ExamManager {
    RoleManager public roleManager;
    AuditLog public auditLog;

    struct Exam {
        string cid;
        address teacher;
        string name;
        uint256 timestamp;
        bool active;
    }

    mapping(uint256 => Exam) public exams;
    uint256 public examCount;

    constructor(address _roleManagerAddress, address _auditLogAddress) {
        roleManager = RoleManager(_roleManagerAddress);
        auditLog = AuditLog(_auditLogAddress);
    }

    modifier onlyTeacher() {
        require(
            keccak256(abi.encodePacked(roleManager.getRole(msg.sender))) == keccak256(abi.encodePacked("TEACHER")),
            "Only Teacher can upload exams"
        );
        _;
    }

    function uploadExam(string memory _cid, string memory _name) external onlyTeacher {
        examCount++;
        exams[examCount] = Exam({
            cid: _cid,
            teacher: msg.sender,
            name: _name,
            timestamp: block.timestamp,
            active: true
        });
        auditLog.logEvent("ExamUploaded", address(this), string(abi.encodePacked("Uploaded exam ", _name)));
    }

    function toggleExamStatus(uint256 _id) external onlyTeacher {
        require(exams[_id].teacher == msg.sender, "Not your exam");
        exams[_id].active = !exams[_id].active;
        string memory desc = exams[_id].active ? "Activated exam" : "Deactivated exam";
        auditLog.logEvent("ExamStatusChanged", address(this), desc);
    }
}
